// Get the item coming into this node (from the Duplicate? IF node)
const currentItem = $input.first().json;

// Always pull the Postcode from the original Airtable trigger
const triggerItem = $('Watch for New Records').first().json;
const fullPostcode = triggerItem.fields?.Postcode;

if (!fullPostcode) {
  // Failsafe: don't crash the workflow if Postcode is missing
  return {
    json: {
      ...currentItem,
      postcodeDistrict: null,
    },
  };
}

// Extract postcode district (e.g., "SW1A 1AA" → "SW1")
const postcodeDistrict = fullPostcode
  .toString()
  .split(' ')[0]      // "SW1A"
  .toUpperCase()
  .replace(/[A-Z]+$/, ''); // "SW1"

return {
  json: {
    ...currentItem,
    postcodeDistrict,
  },
};

