// Ticket that just triggered the workflow
const triggerItem = $('Watch for New Records').first().json;
const triggerFields = triggerItem.fields || triggerItem;

// All open tickets from "Search duplicate tickets"
const allTickets = $input
  .all()
  .map(item => item.json)
  .filter(rec => rec && rec.id);

// Helper
const norm = (v) => (v ?? '').toString().trim().toLowerCase();
const getFields = (rec) => rec.fields || rec;

// Current ticket ID
const currentId = triggerItem.id;

// Find real duplicates
const potentialDuplicates = allTickets.filter((rec) => {
  if (rec.id === currentId) return false;

  const f = getFields(rec);

  const sameTenant   = norm(f['Tenant Email'])    === norm(triggerFields['Tenant Email']);
  const sameAddress  = norm(f['Property Address'])=== norm(triggerFields['Property Address']);
  const sameCategory = norm(f['Issue Category'])  === norm(triggerFields['Issue Category']);

  return sameTenant && sameAddress && sameCategory;
});

// Start from the trigger and add flags
const base = {
  ...triggerItem,
  hasDuplicate: false,
  originalRecordId: null,
  originalTicketNumber: null,
  // store just the fields of each duplicate ticket
  duplicates: potentialDuplicates.map(rec => getFields(rec)),
};

if (!potentialDuplicates.length) {
  return [{ json: base }];
}

// Pick most recent duplicate
potentialDuplicates.sort((a, b) => {
  const fa = getFields(a);
  const fb = getFields(b);
  return new Date(fb['Submitted At'] || '') - new Date(fa['Submitted At'] || '');
});

const original = potentialDuplicates[0];
const of = getFields(original);

base.hasDuplicate = true;
base.originalRecordId = original.id;
base.originalTicketNumber = of['Ticket ID'] ?? triggerFields['Ticket ID'] ?? null;

return [{ json: base }];
